export function parseHTMLProgram(htmlString) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(htmlString, "text/html");

  const weeks = [];
  const weekBlocks = doc.querySelectorAll(".week-block");

  weekBlocks.forEach((weekEl, i) => {
    const sessions = [];
    const seances = weekEl.querySelectorAll(".seance-block");

    seances.forEach((s, j) => {
      const exos = [];
      const exItems = s.querySelectorAll(".exercise-item");

      exItems.forEach((ex, k) => {
        const name = ex.querySelector('[id^="en-"]')?.value || "";
        if (!name) return;

        exos.push({
          name,
          sets: 3,
          reps: "8-10"
        });
      });

      sessions.push({
        name: "Séance " + (j + 1),
        exercises: exos
      });
    });

    weeks.push({
      weekNumber: i + 1,
      sessions
    });
  });

  return { weeks };
}

export function parseHTMLFile(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        resolve(parseHTMLProgram(e.target.result));
      } catch (err) {
        reject(err);
      }
    };
    reader.readAsText(file);
  });
}
